import { GoogleGenAI, Type } from "@google/genai";
import { SchemeMetadata, Lesson } from "../types";

export interface ExtractedSyllabusInfo {
  subject: string;
  form: string;
  recommendedWeeks: number;
}

// Peak into the syllabus to pre-fill the form
export const extractSyllabusInfo = async (
  syllabusFile: { data: string, mimeType: string }
): Promise<ExtractedSyllabusInfo> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        { text: "Analyze this syllabus document. Identify the core subject, the target grade or 'form', and recommend a logical duration in weeks (typically 10-14) to cover the material effectively." },
        { inlineData: syllabusFile }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          subject: { type: Type.STRING },
          form: { type: Type.STRING },
          recommendedWeeks: { type: Type.INTEGER },
        },
        required: ["subject", "form", "recommendedWeeks"],
      }
    }
  });

  try {
    return JSON.parse(response.text.trim());
  } catch (error) {
    console.error("Extraction failed", error);
    return { subject: "", form: "", recommendedWeeks: 12 };
  }
};

// Step 1: Generate the Scheme Book Table
export const generateSchemeBook = async (
  metadata: SchemeMetadata, 
  syllabusFile?: { data: string, mimeType: string }
): Promise<Partial<Lesson>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const totalLessons = metadata.weeks * metadata.lessonsPerWeek;

  const textPrompt = `
    Act as a Senior Curriculum Specialist and Instructional Designer. 
    Create a professional, high-quality Scheme of Work for:
    Subject: ${metadata.subject} 
    Level: Form/Grade ${metadata.form} 
    Term: ${metadata.term}
    Total Capacity: ${totalLessons} lessons over ${metadata.weeks} weeks.

    ${syllabusFile ? 'CRITICAL: Align the content strictly with the topics and learning outcomes identified in the attached syllabus.' : 'Use standard international curriculum standards for this subject and grade level.'}

    DESIGN PRINCIPLES:
    1. PROGRESSION: Ensure a logical scaffolding of concepts (from foundational to complex).
    2. SMART OBJECTIVES: Learning objectives must be Specific, Measurable, Achievable, Relevant, and Time-bound.
    3. ENGAGEMENT: Activities should be student-centered and diverse (collaborative, inquiry-based, practical).
    4. ASSESSMENT: Include formative assessment methods.

    OUTPUT: Provide exactly ${totalLessons} lessons in a structured JSON array.
  `;

  const contents = syllabusFile 
    ? { parts: [{ text: textPrompt }, { inlineData: syllabusFile }] }
    : textPrompt;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            week: { type: Type.INTEGER },
            lessonNumber: { type: Type.INTEGER },
            topic: { type: Type.STRING },
            objectives: { type: Type.STRING, description: "Action-oriented objectives (e.g., 'Students will be able to...')" },
            concepts: { type: Type.STRING, description: "Key vocabulary and theoretical pillars" },
            activities: { type: Type.STRING, description: "Detailed student-teacher interaction flow" },
            resources: { type: Type.STRING, description: "Specific teaching aids and tech tools" },
            assessment: { type: Type.STRING, description: "Formative/Summative check-ins" },
            homework: { type: Type.STRING, description: "Extension or reinforcement task" },
            evaluation: { type: Type.STRING, description: "Criteria for lesson success" },
          },
          required: ["week", "lessonNumber", "topic", "objectives", "concepts", "activities", "resources", "assessment", "homework", "evaluation"],
        }
      }
    }
  });

  try {
    return JSON.parse(response.text.trim());
  } catch (error) {
    throw new Error("Failed to parse scheme book. Please try again.");
  }
};

// Step 2: Generate resources for a specific lesson
export const generateLessonResourcesContent = async (
  lesson: Lesson,
  metadata: SchemeMetadata
): Promise<Pick<Lesson, 'lessonPlanContent' | 'worksheetContent' | 'slidesContent' | 'videoGuideDescription'>> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `
      Act as an expert Teacher Trainer. Generate comprehensive, high-engagement teaching resources for:

      CONTEXT:
      - Subject: ${metadata.subject} (Form ${metadata.form})
      - Lesson Topic: ${lesson.topic}
      - Key Objectives: ${lesson.objectives}
      - Key Concepts: ${lesson.concepts}

      PEDAGOGICAL REQUIREMENTS:

      1. 'lessonPlanContent' (Markdown): 
         - Use a standard format: 
           - Anticipatory Set/Hook (5 mins): Engage prior knowledge.
           - Direct Instruction (10-15 mins): Core explanation with teacher scripts.
           - Guided Practice (15 mins): Collaborative task with scaffolding.
           - Independent Practice (10 mins): Student check.
           - Closure/Plenary (5 mins): Recap and 'exit ticket'.
           - Misconceptions: List 2 common pitfalls and how to address them.
           - Differentiation: One strategy for 'Support' and one for 'Challenge'.

      2. 'worksheetContent' (Markdown): 
         - Title the worksheet clearly.
         - Include 5-6 questions of increasing difficulty (Bloom's Taxonomy):
           - 2 Recall/Understanding questions.
           - 2 Application/Analysis questions.
           - 1 Evaluation/Creation 'Challenge' question.
         - Provide clear blank spaces for student answers.

      3. 'slidesContent' (Array of 6 strings):
         - Slide 1: Title & Hook.
         - Slide 2: Learning Objectives (in student-friendly 'I can' language).
         - Slide 3: Key Concepts/Vocabulary definitions.
         - Slide 4: Main Instructional Diagram or Process explanation.
         - Slide 5: Guided Activity instructions.
         - Slide 6: Summary & Homework.

      4. 'videoGuideDescription' (Text):
         - A structured narrative outline for a teacher recording a 3-minute explanation video. 
         - Include what to say and what to point at on a screen.
    `,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          lessonPlanContent: { type: Type.STRING },
          worksheetContent: { type: Type.STRING },
          slidesContent: { type: Type.ARRAY, items: { type: Type.STRING } },
          videoGuideDescription: { type: Type.STRING },
        },
        required: ["lessonPlanContent", "worksheetContent", "slidesContent", "videoGuideDescription"],
      }
    }
  });

  return JSON.parse(response.text.trim());
};
